import{_ as e,o as a,c as i,a2 as o}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Random Image API e gallery pubblica","description":"","frontmatter":{},"headers":[],"relativePath":"it-IT/Other/random-image-api-and-public-gallery.md","filePath":"it-IT/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),d={name:"it-IT/Other/random-image-api-and-public-gallery.md"};function r(l,t,n,s,c,p){return a(),i("div",null,[...t[0]||(t[0]=[o(`<h1 id="random-image-api-e-gallery-pubblica" tabindex="-1">Random Image API e gallery pubblica <a class="header-anchor" href="#random-image-api-e-gallery-pubblica" aria-label="Permalink to &quot;Random Image API e gallery pubblica&quot;">​</a></h1><p>Entrambe le funzioni si configurano in:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings</span></span></code></pre></div><h2 id="random-image-api" tabindex="-1">Random Image API <a class="header-anchor" href="#random-image-api" aria-label="Permalink to &quot;Random Image API&quot;">​</a></h2><p>La Random Image API restituisce un file casuale dalle directory selezionate. È utile per sfondi sito, rotazione avatar o richiami casuali da pagine esterne.</p><p>Dopo l&#39;abilitazione, usa:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/random</span></span></code></pre></div><h2 id="impostazioni-random-image-api" tabindex="-1">Impostazioni Random Image API <a class="header-anchor" href="#impostazioni-random-image-api" aria-label="Permalink to &quot;Impostazioni Random Image API&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opzione</th><th>Scopo</th></tr></thead><tbody><tr><td>Enable</td><td>Attiva o disattiva l&#39;endpoint <code>/random</code>. Se disattivo, l&#39;accesso è vietato.</td></tr><tr><td>Directories</td><td>Limita le directory utilizzabili dall&#39;API. Directory non incluse qui non possono essere scelte.</td></tr><tr><td>Call demo</td><td>Genera link Random API copiabili direttamente.</td></tr></tbody></table><p>Puoi selezionare più directory. Per esempio, se sono consentite solo <code>/landscape/</code> e <code>/portrait/</code>, l&#39;API può scegliere file solo da quelle directory e dalle relative sottocartelle.</p><h2 id="parametri-random-image-api" tabindex="-1">Parametri Random Image API <a class="header-anchor" href="#parametri-random-image-api" aria-label="Permalink to &quot;Parametri Random Image API&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parametro</th><th>Esempio</th><th>Scopo</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>Specifica la directory casuale.</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td>Specifica il tipo media. Usa <code>image</code>, <code>video</code>, <code>audio</code> o combinazioni separate da virgola.</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td>Filtra l&#39;orientamento immagine. Usa <code>portrait</code>, <code>landscape</code> o <code>auto</code>.</td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>Formato di risposta. Vuoto significa redirect, <code>url</code> restituisce URL testuale, <code>json</code> restituisce JSON.</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td>Con <code>type=url</code>, restituisce un URL completo.</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>Filtra per rating età.</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>Restituisce solo file con questi tag.</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>Esclude file con questi tag.</td></tr></tbody></table><h2 id="formati-di-risposta" tabindex="-1">Formati di risposta <a class="header-anchor" href="#formati-di-risposta" aria-label="Permalink to &quot;Formati di risposta&quot;">​</a></h2><p>Senza <code>type</code>, l&#39;API reindirizza direttamente all&#39;URL del file casuale.</p><p>Con <code>type=url</code>, restituisce un URL come testo.</p><p>Con <code>type=json</code>, restituisce informazioni del file: URL, ID, nome, tipo, tag, rating e metadati collegati.</p><h2 id="regole-di-accesso" tabindex="-1">Regole di accesso <a class="header-anchor" href="#regole-di-accesso" aria-label="Permalink to &quot;Regole di accesso&quot;">​</a></h2><p>La Random Image API rispetta le regole di accesso pubblico:</p><table tabindex="0"><thead><tr><th>Regola</th><th>Effetto</th></tr></thead><tbody><tr><td>Restrizione directory</td><td>Possono essere scelti solo file nelle directory consentite.</td></tr><tr><td>Blocklist</td><td>I file in blocklist sono esclusi dal pool casuale.</td></tr><tr><td>Modalità allowlist</td><td>Quando attiva, vengono restituiti solo file consentiti per accesso pubblico.</td></tr><tr><td>Rating età</td><td>R12, R16, R18 e contenuti simili vengono filtrati dalla modalità di accesso corrente.</td></tr></tbody></table><p>Se dopo i filtri non resta nessun file, l&#39;API restituisce nessun risultato corrispondente.</p><h2 id="cache" tabindex="-1">Cache <a class="header-anchor" href="#cache" aria-label="Permalink to &quot;Cache&quot;">​</a></h2><p>La Random Image API memorizza in cache i pool candidati delle directory per migliorare la velocità.</p><p>Dopo modifiche ai file, ImgBed aggiorna la versione cache della directory e le richieste successive ricostruiscono il pool. Le directory vuote vengono mantenute in cache per poco tempo, così da evitare query ripetute.</p><h2 id="gallery-pubblica" tabindex="-1">Gallery pubblica <a class="header-anchor" href="#gallery-pubblica" aria-label="Permalink to &quot;Gallery pubblica&quot;">​</a></h2><p>La gallery pubblica offre una pagina di sola lettura per le directory che vuoi mostrare ai visitatori.</p><p>Dopo l&#39;abilitazione, i visitatori possono aprire:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/directory-name</span></span></code></pre></div><h2 id="impostazioni-gallery-pubblica" tabindex="-1">Impostazioni gallery pubblica <a class="header-anchor" href="#impostazioni-gallery-pubblica" aria-label="Permalink to &quot;Impostazioni gallery pubblica&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opzione</th><th>Scopo</th></tr></thead><tbody><tr><td>Enable</td><td>Attiva o disattiva la gallery pubblica. Se disattiva, i visitatori non possono sfogliarla.</td></tr><tr><td>Image loading mode</td><td>Decide se le anteprime usano immagini originali o miniature.</td></tr><tr><td>Open directories</td><td>Definisce quali directory sono accessibili ai visitatori.</td></tr></tbody></table><h2 id="modalita-caricamento-immagini" tabindex="-1">Modalità caricamento immagini <a class="header-anchor" href="#modalita-caricamento-immagini" aria-label="Permalink to &quot;Modalità caricamento immagini&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Modalità</th><th>Scopo</th></tr></thead><tbody><tr><td>Original</td><td>La pagina visitatore carica direttamente i file originali.</td></tr><tr><td>Thumbnail</td><td>La pagina visitatore preferisce miniature per caricare più velocemente.</td></tr></tbody></table><h2 id="directory-aperte" tabindex="-1">Directory aperte <a class="header-anchor" href="#directory-aperte" aria-label="Permalink to &quot;Directory aperte&quot;">​</a></h2><p>Le directory aperte decidono cosa possono vedere i visitatori.</p><p>Esempio:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>I visitatori potranno accedere a:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/1</span></span>
<span class="line"><span>https://your-domain.com/browse/2</span></span>
<span class="line"><span>https://your-domain.com/browse/landscape</span></span>
<span class="line"><span>https://your-domain.com/browse/portrait</span></span></code></pre></div><p>Sono supportate anche sottodirectory, come <code>/2026/lucky/</code>. Le directory non aperte restano bloccate.</p><h2 id="funzioni-della-gallery-pubblica" tabindex="-1">Funzioni della gallery pubblica <a class="header-anchor" href="#funzioni-della-gallery-pubblica" aria-label="Permalink to &quot;Funzioni della gallery pubblica&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Funzione</th><th>Descrizione</th></tr></thead><tbody><tr><td>Navigazione directory</td><td>Mostra file e sottocartelle nelle directory aperte.</td></tr><tr><td>Ricerca</td><td>Cerca per nome file, ID file o tag.</td></tr><tr><td>Filtro tipo</td><td>Filtra immagini, video, audio o altri file.</td></tr><tr><td>Filtro tag</td><td>Include o esclude tag selezionati.</td></tr><tr><td>Filtro orientamento</td><td>Filtra immagini orizzontali o verticali.</td></tr><tr><td>Filtro tempo</td><td>Filtra per intervallo di upload.</td></tr><tr><td>Filtro estensione</td><td>Filtra per estensione file.</td></tr><tr><td>Copia link</td><td>Copia link di accesso ai file.</td></tr><tr><td>Anteprima media</td><td>Visualizza o riproduce immagini, video e audio nella pagina visitatore.</td></tr></tbody></table><h2 id="regole-di-accesso-della-gallery-pubblica" tabindex="-1">Regole di accesso della gallery pubblica <a class="header-anchor" href="#regole-di-accesso-della-gallery-pubblica" aria-label="Permalink to &quot;Regole di accesso della gallery pubblica&quot;">​</a></h2><p>Anche la gallery pubblica rispetta le regole di accesso:</p><table tabindex="0"><thead><tr><th>Regola</th><th>Effetto</th></tr></thead><tbody><tr><td>Directory aperte</td><td>Vengono mostrate solo directory consentite.</td></tr><tr><td>Access mode</td><td>I contenuti sono filtrati dalla modalità di accesso per rating età.</td></tr><tr><td>Modalità allowlist</td><td>Quando attiva, vengono mostrati solo file consentiti per accesso pubblico.</td></tr><tr><td>Blocklist</td><td>I file in blocklist sono nascosti.</td></tr></tbody></table>`,43)])])}const u=e(d,[["render",r]]);export{h as __pageData,u as default};
